steps.command:
SELECT pid, now() - pg_stat_activity.query_start AS duration
FROM pg_stat_activity
WHERE pid IN (277, 279);

SELECT pid, usename, datname, state, query, xact_start, wait_event_type, wait_event
FROM pg_stat_activity
WHERE state IN ('active', 'idle in transaction');

SELECT pid, usename, query, xact_start, wait_event_type, wait_event
FROM pg_stat_activity
WHERE pid IN (290, 288);

BEGIN;

-- Lock the specific row first
SELECT * FROM bookings.bookings WHERE book_ref = '361A07' FOR UPDATE;

-- Perform the update after acquiring the lock
UPDATE bookings.bookings SET total_amount = total_amount WHERE book_ref = '361A07';

COMMIT;

SELECT name, setting, unit
FROM pg_settings
WHERE name LIKE 'autovacuum%';

SELECT pid, usename, state, query
FROM pg_stat_activity
WHERE state != 'idle';

SELECT pid
FROM pg_stat_activity
WHERE state = 'idle in transaction';

SELECT pg_terminate_backend(pid)
FROM pg_stat_activity
WHERE state = 'idle in transaction';

