steps.command:
SELECT oid
FROM pg_class
WHERE relname = 'bookings' AND relnamespace = (SELECT oid FROM pg_namespace WHERE nspname = 'bookings');

SELECT pid, now() - pg_stat_activity.query_start AS duration, query
FROM pg_stat_activity
WHERE state = 'active' AND (now() - pg_stat_activity.query_start) > interval '5 minutes';

SELECT
    pg_size_pretty(pg_database_size(current_database())) AS db_size,
    pg_stat_get_backend_activity() AS backend_activity;

SELECT count(*) AS active_connections
FROM pg_stat_activity
WHERE state != 'idle';

SELECT pid, age(now(), xact_start) AS transaction_age, query
FROM pg_stat_activity
WHERE state = 'active' AND now() - xact_start > interval '5 minutes';
